// Python solution
import sys
from collections import deque

class Solution:
    def __init__(self):
        pass

    def solve(self, n):
        q = deque([])
        first_line = sys.stdin.readline().strip()  # read the first line
        elements = first_line.split(' ')
        for element in elements:
            q.append(element)
        second_line = sys.stdin.readline().strip()  # read the second line
        elements = second_line.split(' ')
        for element in elements:
            q.append(element)
        return q.pop()

if __name__ == '__main__':
    solution = Solution()
    n = int(sys.stdin.readline().strip())
    num = solution.solve(n)
    print(num)

