// C++ solution
#include <iostream>
#include <vector>
#include <deque>
using namespace std;

class Solution
{
public:
bool solve(vector<int> &n)
{
    deque<int> q;
    string firstLine;
    getline(cin, firstLine);
    size_t spacePos = firstLine.find(' ');
    for(size_t i=spacePos;i!=string::npos;i=firstLine.find(' ', i))
    {
        q.push_front(firstLine.substr(0, i));
        firstLine.erase(0, i+1);
    }
    q.push_front(firstLine);
    string secondLine;
    getline(cin, secondLine);
    size_t spacePos2 = secondLine.find(' ');
    for(size_t i=spacePos2;i!=string::npos;i=secondLine.find(' ', i))
    {
        q.push_front(secondLine.substr(0, i));
        secondLine.erase(0, i+1);
    }
    q.push_front(secondLine);
    return q.back();
}
};

int main()
{
    Solution solution;
    int n;
    cin >> n;  // read the first line
    cin.ignore();  // ignore the newline character
    string line;
    getline(cin, line);
    size_t spacePos = line.find(' ');
    for(size_t i=spacePos;i!=string::npos;i=line.find(' ', i))
    {
        solution.solve(line.substr(0, i));
        line.erase(0, i+1);
    }
    solution.solve(line);
    cout << solution.solve(n) << endl;
    return 0;
}
